```js
const cors = require('cors');

const corsOptions = {
  origin: process.env.ALLOWED_ORIGIN || 'https://yourdomain.com', // explicit allowlist
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
